sql:
SELECT power_source_id, COUNT(mill_id) AS mill_count
FROM mills
GROUP BY power_source_id;

SELECT description 
FROM mill_types 
WHERE type_name = 'Post mill';

SELECT title, construction_date, last_restoration_date
FROM mills
ORDER BY construction_date ASC;

SELECT mill_id, start_date
FROM mill_ownerships
WHERE end_date IS NOT NULL AND end_date <> '';

SELECT function_name, description, JULIANDAY('now') AS current_julian_day
FROM mill_functions
WHERE function_id = 0;

external_knowledge:
- 'Operational mills' refers to mills that are currently in use;
- 'Stand proud in their locations' means the mills are located in specific places in England;
- 'Shared by more than one caretaker' indicates that each mill has more than one owner.

- "ancient wind-powered mills" refers to mills that use wind as their power source;
- "corn mills" are mills specifically designed to process corn;
- "guardians" refers to the owners of the mills;
- "held their posts" refers to the duration of ownership, calculated as the difference between the start and end dates of ownership;
- "cumulative cost of maintaining" refers to the total cost of maintenance, summed over time for each mill.

- The 18th century spans from 1700 to 1799;
- "Wind-powered mills" refers to mills that use wind as their primary source of power;
- "Stand tall in England" is a metaphorical way to describe mills that are located in England.

- "Operational mills" refers to mills with a status of 'operational';
- "Longest tenure" refers to the owner who has owned the mill for the longest period;
- "Restored" means the mill has a recorded restoration date.

- "brought back to life" refers to mills that have undergone restorations;
- "standing tall" refers to mills that are currently operational;
- Suffolk is a county in England.

- "the newest at their respective locations" refers to the most recently constructed mills within each location;
- "rejuvenated after the dawn of the decade" refers to restoration dates after January 1, 2010;
- "rejuvenation" refers to the restoration of mills;
- "exceeded $10,000" refers to restoration costs greater than $10,000.

